# Category: integer_overflow

#include <stdio.h>
#include <stdlib.h>

double **allocate2DMatrix(int rows, int cols) {
    // Allocate memory for row pointers
    double **matrix = malloc(rows * sizeof(double *));
    if (matrix == NULL) {
        return NULL;
    }
    // Allocate contiguous memory for all elements
    double *data = malloc(rows * cols * sizeof(double));
    if (data == NULL) {
        free(matrix);
        return NULL;
    }
    // Set row pointers to the appropriate positions in the contiguous block
    for (int i = 0; i < rows; i++) {
        matrix[i] = data + i * cols;
    }
    return matrix;
}

int main() {
    int rows, cols;
    printf("Enter the number of rows: ");
    scanf("%d", &rows);
    printf("Enter the number of columns: ");
    scanf("%d", &cols);

    double **matrix = allocate2DMatrix(rows, cols);
    if (matrix == NULL) {
        printf("Memory allocation failed.\n");
        return 1;
    }

    // Example usage: initialize matrix elements to 0.0
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            matrix[i][j] = 0.0;
        }
    }

    // Free the allocated memory
    free(matrix[0]); // free contiguous data block
    free(matrix);    // free row pointers

    return 0;
}